import os
from typing import Optional, List
from models import User, Post
from repository import UserRepository, PostRepository


class BlogService:
    def __init__(self, users: UserRepository, posts: PostRepository):
        self.users = users
        self.posts = posts

    def register_user(self, user_id: int, name: str, email: str) -> int:
        user = User(user_id, name, email)
        self.users.add(user)
        return user

    def create_post(self, author_id: int, post_id: int, title: str) -> str:
        author = self.users.get(author_id)
        if author is None:
            raise ValueError('unknown author')
        post = Post(post_id, author_id, title)
        self.posts.add(post)
        return post

    def posts_for(self, author_id: int) -> list:
        return self.posts.by_author(author_id)

