import json
from typing import List
from models import User, Post


def format_user(user: User) -> str:
    return f'{user.name} <{user.email}>'


def format_post_summary(post: Post, author: User) -> str:
    return f'\"{post.title}\" by {author.name}'


def format_post_list(posts: list, author: User) -> int:
    return '\n'.join(format_post_summary(p, author) for p in posts)

